import "./Home.css";
import Navbar from "../Components/Navbar/Navbar";
import { IoIosArrowForward, IoIosArrowBack } from "react-icons/io";
export default function Home() {
  const categories = {
    women: [
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTozXgYNiSlARaFWKTz-AuV6ovveunDlm04Lw&usqp=CAU",
      "data:image/jpeg;base64,",
      // Add more women's category image URLs as needed
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTozXgYNiSlARaFWKTz-AuV6ovveunDlm04Lw&usqp=CAU",
      "data:image/jpeg;base64,",
      // Add more women's category image URLs as needed
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTozXgYNiSlARaFWKTz-AuV6ovveunDlm04Lw&usqp=CAU",
      "data:image/jpeg;base64,",
      // Add more women's category image URLs as needed
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTozXgYNiSlARaFWKTz-AuV6ovveunDlm04Lw&usqp=CAU",
      "data:image/jpeg;base64,",
      // Add more women's category image URLs as needed
    ],
    men: [
      "data:image/jpeg;base64,",
      "data:image/jpeg;base64,",
      // Add more men's category image URLs as needed
      "data:image/jpeg;base64,",
      "data:image/jpeg;base64,",
      // Add more men's category image URLs as needed
      "data:image/jpeg;base64,",
      "data:image/jpeg;base64,",
      // Add more men's category image URLs as needed
      "data:image/jpeg;base64,",
      "data:image/jpeg;base64,",
      // Add more men's category image URLs as needed
      "data:image/jpeg;base64,",
      "data:image/jpeg;base64,",
      // Add more men's category image URLs as needed
    ],

    kids: [
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS_AuQtUnZtsi_Q8Wx7lkaUmlJWrO5oRiuRtQ&usqp=CAU",
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTdLx48iAqwEaJaEcCP-m8v8n15JRpHodq6sw&usqp=CAU",
      // Add more kids' category image URLs as needed
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS_AuQtUnZtsi_Q8Wx7lkaUmlJWrO5oRiuRtQ&usqp=CAU",
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTdLx48iAqwEaJaEcCP-m8v8n15JRpHodq6sw&usqp=CAU",
      // Add more kids' category image URLs as needed
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS_AuQtUnZtsi_Q8Wx7lkaUmlJWrO5oRiuRtQ&usqp=CAU",
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTdLx48iAqwEaJaEcCP-m8v8n15JRpHodq6sw&usqp=CAU",
      // Add more kids' category image URLs as needed
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS_AuQtUnZtsi_Q8Wx7lkaUmlJWrO5oRiuRtQ&usqp=CAU",
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTdLx48iAqwEaJaEcCP-m8v8n15JRpHodq6sw&usqp=CAU",
      // Add more kids' category image URLs as needed
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS_AuQtUnZtsi_Q8Wx7lkaUmlJWrO5oRiuRtQ&usqp=CAU",
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTdLx48iAqwEaJaEcCP-m8v8n15JRpHodq6sw&usqp=CAU",
      // Add more kids' category image URLs as needed
    ],
  };

  const [currentCategory, setCurrentCategory] = useState("women");
  const [autoplayEnabled, setAutoplayEnabled] = useState(true);
  const [manualScroll, setManualScroll] = useState(false);
  const swiperRef = useRef(null);

  const handleCategoryChange = (category) => {
    setCurrentCategory(category);
    setAutoplayEnabled(true); // Enable autoplay when changing category through button click
    setManualScroll(false); // Reset manualScroll flag

    // Reset Swiper to the first slide of the new category
    const swiper = swiperRef.current?.swiper;
    if (swiper) {
      swiper.slideTo(0);
    }
  };

  const getSlides = (category, imageUrls) => {
    return imageUrls.map((imageUrl, index) => (
      <SwiperSlide key={`${category}-slide-${index}`}>
        <img src={imageUrl} alt="" />
      </SwiperSlide>
    ));
  };

  const getCategorySlides = () => {
    const imageUrls = categories[currentCategory] || [];
    return getSlides(currentCategory, imageUrls);
  };

  useEffect(() => {
    const swiper = swiperRef.current?.swiper;
    const activeIndex = swiper.activeIndex;

    if (activeIndex === 0 && autoplayEnabled && !manualScroll) {
      swiper.autoplay.start(); // Start autoplay only if it's the first slide (active category) and not manually scrolled
    } else {
      swiper.autoplay.stop(); // Stop autoplay if manually scrolled
    }
  }, [currentCategory, autoplayEnabled, manualScroll]);

  const handleScroll = () => {
    setManualScroll(true);
    setTimeout(() => {
      setManualScroll(false);
    }, 500); // Adjust the timeout value based on your needs to determine when a manual scroll occurs
  };
  const handleNextCategory = () => {
    const categoriesList = Object.keys(categories);
    const currentIndex = categoriesList.indexOf(currentCategory);
    const nextIndex = (currentIndex + 1) % categoriesList.length;
    handleCategoryChange(categoriesList[nextIndex]);
  };

  const handlePrevCategory = () => {
    const categoriesList = Object.keys(categories);
    const currentIndex = categoriesList.indexOf(currentCategory);
    const prevIndex =
      (currentIndex - 1 + categoriesList.length) % categoriesList.length;
    handleCategoryChange(categoriesList[prevIndex]);
  };
  return (
    <div className="Home">
      <div className="sticky top-0 z-10">
        <div className="absolute w-full">
          <Navbar />
        </div>
      </div>
      <div className="SwiperArea">
        <div className="NavigationButtons">
          <div className=" z-20">
            <IoIosArrowBack
              onClick={handlePrevCategory}
              className="arrow-icon"
            />
          </div>
          <div className="z-20">
            <IoIosArrowForward
              onClick={handleNextCategory}
              className="arrow-icon"
            />
          </div>
        </div>
        <Swiper
          ref={swiperRef}
          direction={"vertical"}
          slidesPerView={1}
          spaceBetween={0}
          mousewheel={true}
          centeredSlides={true}
          autoplay={{
            delay: 3000,
            disableOnInteraction: false,
          }}
          modules={[Mousewheel, Autoplay, Pagination]}
          className="mySwiper relative"
          onSlideChange={() => {}}
          onTransitionEnd={() => {}}
          pagination={false}
          onScroll={() => handleScroll()}
        >
          {getCategorySlides()}
        </Swiper>
      </div>
    </div>
  );
}
